// HasPurchaseReceipt applies the HasEdge predicate on the "purchase_receipt" edge.
func HasPurchaseReceipt() predicate.PurchaseReceiptAdjustment {
	return predicate.PurchaseReceiptAdjustment(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, PurchaseReceiptTable, PurchaseReceiptColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasPurchaseReceiptWith applies the HasEdge predicate on the "purchase_receipt" edge with a given conditions (other predicates).
func HasPurchaseReceiptWith(preds ...predicate.PurchaseReceipt) predicate.PurchaseReceiptAdjustment {
	return predicate.PurchaseReceiptAdjustment(func(s *sql.Selector) {
		step := newPurchaseReceiptStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// HasItems applies the HasEdge predicate on the "items" edge.
func HasItems() predicate.PurchaseReceiptAdjustment {
	return predicate.PurchaseReceiptAdjustment(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, ItemsTable, ItemsColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasItemsWith applies the HasEdge predicate on the "items" edge with a given conditions (other predicates).
func HasItemsWith(preds ...predicate.PurchaseReceiptAdjustmentItem) predicate.PurchaseReceiptAdjustment {
	return predicate.PurchaseReceiptAdjustment(func(s *sql.Selector) {
		step := newItemsStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

